const e={english:"English",spanish:"Español",french:"Français",armenian:"Հայերեն",japanese:"日本語",russian:"Русский",ukrainian:"Українська",chinese:"中文"},i={title:"The Ultimate Anime Experience",description:"Ota-Ku provides the ultimate anime experience for watching your favorite anime series and movies on demand, anytime, anywhere. With Ota-Ku, you can explore a vast library of anime content, including the latest releases, classic favorites, and hidden gems. Create your own personalized watchlist to easily access the anime you love and stay up-to-date with your favorite series.","start-watching-now":"Start Watching Now","streaming-features":{title:"We Provide you streaming experience across various devices.",description:"With StreamVibe, you can enjoy your favorite movies and TV shows anytime, anywhere. Our platform is designed to be compatible with a wide range of devices, ensuring that you never miss a moment of entertainment.",features:{1:{title:"Smartphones",description:"StreamVibe is optimized for both Android and iOS smartphones. Download our app from the Google Play Store or the Apple App Store"},2:{title:"Tablet",description:"StreamVibe is optimized for both Android and iOS smartphones. Download our app from the Google Play Store or the Apple App Store"},3:{title:"Smart TV",description:"StreamVibe is optimized for both Android and iOS smartphones. Download our app from the Google Play Store or the Apple App Store"},4:{title:"Laptops",description:"StreamVibe is optimized for both Android and iOS smartphones. Download our app from the Google Play Store or the Apple App Store"},5:{title:"Gaming Consoles",description:"StreamVibe is optimized for both Android and iOS smartphones. Download our app from the Google Play Store or the Apple App Store"},6:{title:"VR Headsets",description:"StreamVibe is optimized for both Android and iOS smartphones. Download our app from the Google Play Store or the Apple App Store"}}},faq:{title:"We Provide you streaming experience across various devices.",description:`With StreamVibe, you can enjoy your favorite movies and TV shows anytime, anywhere. Our platform is designed to be compatible with a wide range of
devices, ensuring that you never miss a moment of entertainment.`}},t={"sign-up":"Sign Up",languages:e,"language-codes":{english:"English",spanish:"Spanish",french:"French",armenian:"Armenian",japanese:"Japanese",russian:"Russian",ukrainian:"Ukrainian",chinese:"Chinese"},welcome:i},o={"sign-up":"щцлвщцв"},n="Bienvenue",a={welcome:n},s="Բարի գալուստ",r={welcome:s},p="ようこそ",l={welcome:p},c={english:"English",spanish:"Español",french:"Français",armenian:"Հայերեն",japanese:"日本語",russian:"Русский",ukrainian:"Українська",chinese:"中文"},d={title:"Максимальное аниме-удовольствие",description:"Ota-Ku предоставляет уникальный опыт просмотра ваших любимых аниме-сериалов и фильмов по запросу, в любое время и в любом месте. С Ota-Ku вы можете исследовать обширную библиотеку аниме-контента, включая последние релизы, классические хиты и скрытые жемчужины. Создайте свой персонализированный список просмотра, чтобы легко получить доступ к аниме, которое вы любите, и всегда быть в курсе ваших любимых сериалов.","start-watching-now":"Начать смотреть сейчас","streaming-features":{title:"Мы предоставляем вам опыт потокового вещания на различных устройствах.",description:"С Ota-Ku вы можете наслаждаться любимыми фильмами и телепередачами в любое время и в любом месте. Наша платформа разработана таким образом, чтобы быть совместимой с множеством устройств, гарантируя, что вы не пропустите ни единого момента развлечений.",features:{1:{title:"Высокая скорость сайта",description:"Испытайте молниеносную скорость работы нашего сайта благодаря передовым технологиям оптимизации и мощным серверам. Быстрая загрузка страниц и медиафайлов обеспечит вам комфортное использование без задержек."},2:{title:"Приложение Android, iOS, TV",description:"Наш сервис доступен через приложения для iOS, Android и смарт-ТВ. Скачайте приложение для удобного просмотра контента на ходу или на большом экране, обеспечивая гибкость и комфорт в любом месте."},3:{title:"Доступность на всех основных платформах",description:"Наше приложение доступно на Google Play Market, App Store, RuStore и AppGallery. Наслаждайтесь удобным доступом к нашему сервису на любом устройстве без ограничений."},4:{title:"Поддержка 4K и HDR",description:"Смотрите аниме в разрешении 4K и HDR для детализированного и яркого изображения. Наслаждайтесь каждым кадром в высоком качестве с максимально насыщенными цветами."},5:{title:"Совместный просмотр",description:"Смотрите аниме вместе с друзьями в реальном времени. Общайтесь через чат и делитесь впечатлениями, наслаждаясь совместным просмотром любимого контента независимо от вашего местоположения."},6:{title:"Регулярные обновления",description:"Оставайтесь в курсе новых релизов и свежих новинок в мире аниме с помощью регулярных обновлений контента. Мы постоянно добавляем актуальные серии и фильмы для вашего удовольствия."},7:{title:"Интуитивно понятный интерфейс",description:"Наш сайт предлагает простую и удобную навигацию, что позволяет легко и быстро находить нужный контент. Интуитивно понятное меню и четкая структура помогают вам с комфортом использовать все функции."},8:{title:"Открытый исходный код",description:"Наш проект имеет открытый исходный код, что обеспечивает полную прозрачность и позволяет пользователям проверять, что мы не занимаемся слежкой и соблюдаем принципы чистоты и безопасности данных."},9:{title:"Скачивание аниме торрентом",description:"Вы можете скачать аниме как через торрент, так и без него. Выбирайте удобный для вас способ загрузки, чтобы наслаждаться любимым контентом оффлайн, с максимальным удобством и гибкостью."},10:{title:"Встроенный и внешние медиа-плееры",description:"Наш сайт предлагает встроенный медиа-плеер. Также поддерживаем интеграцию с внешними плеерами, такими как Kodik, VLC, MX Player и другими, для удобного просмотра аниме через различные источники."},11:{title:"Присоединяйтесь к команде разработчиков",description:"Если вы разработчик, вы можете присоединиться к нашей команде и внести свой вклад в развитие проекта. Оставьте заявку для участия в разработке, улучшении функционала и добавлении новых возможностей для нашего аниме сайта."}}},faq:{title:"Часто задаваемые вопросы",description:"В этом разделе вы найдете ответы на самые распространенные вопросы о нашем сервисе Ota-Ku, включая информацию о подписке, поддерживаемых устройствах, функциях и многом другом. Если у вас есть вопросы, которые здесь не освещены, пожалуйста, свяжитесь с нашей службой поддержки."}},m={"sign-up":"Регистрация",languages:c,"language-codes":{english:"Английский",spanish:"Испанский",french:"Французский",armenian:"Армянский",japanese:"Японский",russian:"Русский",ukrainian:"Украинский",chinese:"Китайский"},welcome:d},h="Ласкаво просимо",u={welcome:h},g="欢迎",f={welcome:g},w=()=>({messages:{en:t,es:o,fr:a,hy:r,ja:l,ru:m,uk:u,zh:f}});export{w as default};
